sql:
SELECT COUNT(*) AS total_active_items
FROM drop_items
WHERE is_active = 1;

SELECT item_name, drop_chance, rarity
FROM drop_items
WHERE item_type = 'Weapon' AND rarity = 'Rare';

external_knowledge:
; 
; The ranking category 'Top' refers to the item rarity with the highest number of items and the highest average drop chance for each monster.
;

- 'Crème de la crème' is an idiom that refers to the best of the best, or the most skilled and accomplished people or things in a particular group; 
- 'Top-tier treasures' implies items of exceptionally high quality or value within their respective categories;
- 'Rarest and most legendary items' refers to items with a 'rarity' of either 'Rare' or 'Legendary'.

sql:
SELECT item_name
FROM drop_items
WHERE drop_chance = (SELECT MAX(drop_chance) FROM drop_items);
